  ('00000001-0007-4000-8000-000000000000', '00000001-0001-4000-8000-000000000000', 'Más de 10 formas de monetizar tu vuelo con Next Flight', E'Desbloquea todas las maneras en que puedes generar ingresos con NextFlight: afiliación, productos, retos, servicios y más.\n\n**NO OLVIDES DESCARGAR EN EL BOT ÓN DE ARRIBA  (DOWNLOADS) EL PDF DE ESTA LE', NULL, NULL, 0, false, 'Dua Daniela P.', 'Fundadora', NULL, 7, true),
